{"code": "import json

# Load children's books
children_books = var_functions.query_db_16
children_book_ids = {book['book_id'] for book in children_books}
print(f"Found {len(children_book_ids)} children's books")

# Load reviews from 2020 onwards (stored in file)
review_file_path = var_functions.query_db_18
with open(review_file_path, 'r') as f:
    reviews_2020 = json.load(f)

print(f"Found {len(reviews_2020)} reviews from 2020 onwards")

# Filter reviews for children's books only
children_reviews = []
for review in reviews_2020:
    if review['purchase_id'] in children_book_ids:
        children_reviews.append({
            'purchase_id': review['purchase_id'],
            'rating': float(review['rating'])
        })

print(f"Found {len(children_reviews)} reviews for children's books")

# Calculate average rating per book
from collections import defaultdict
book_ratings = defaultdict(list)
for review in children_reviews:
    book_ratings[review['purchase_id']].append(review['rating'])

# Calculate averages and filter books with avg >= 4.5
book_averages = {}
for book_id, ratings in book_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        book_averages[book_id] = {
            'avg_rating': avg_rating,
            'review_count': len(ratings)
        }

print(f"Found {len(book_averages)} children's books with avg rating >= 4.5")

# Get book titles
book_titles = {book['book_id']: book['title'] for book in children_books}

# Prepare final result
result = []
for book_id, stats in book_averages.items():
    if book_id in book_titles:
        result.append({
            'book_id': book_id,
            'title': book_titles[book_id],
            'avg_rating': round(stats['avg_rating'], 2),
            'review_count': stats['review_count']
        })

# Sort by average rating descending
result.sort(key=lambda x: x['avg_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

